export const meta = {
  name: 'qa-bean-validation-test',
  description: 'QA workflow: Bean Validation Form unit test',
  phases: [
    { title: 'SemanticSearch', detail: 'Search knowledge files for Bean Validation testing' },
    { title: 'ReadSections', detail: 'Read selected sections' },
    { title: 'GenerateAnswer', detail: 'Generate and verify answer' }
  ]
}

phase('SemanticSearch')

const searchResult = await agent(
  `You are executing a semantic search over Nablarch 6 knowledge files.

Query: "Bean ValidationのFormクラスの単体テストを書きたい。テストクラスの作り方とテストデータの準備方法を教えてほしい（目的: テストを書きたい）"

Search in directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/

Steps:
1. List all JSON files in the knowledge directory using glob pattern **/*.json
2. For each file, read the filename and first ~200 chars to understand the topic
3. Select pages relevant to: Bean Validation, Form class unit testing, test data preparation, validation testing
4. For selected pages, identify relevant sections (section_id like s1, s2, etc.)
5. Rate each section as "high" (directly answers the query) or "partial" (partially relevant)

Return a JSON object with this exact structure:
{
  "selected_pages": [
    {"path": "<relative path from knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<relative path from knowledge/>", "reason": "<why excluded>"}
  ],
  "selected_sections": [
    {"file": "<full file path>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}
  ],
  "excluded_sections": [
    {"file": "<full file path>", "section_id": "<sN>", "reason": "<why skipped>"}
  ]
}`,
  {
    label: 'semantic-search',
    phase: 'SemanticSearch',
    schema: {
      type: 'object',
      properties: {
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
    }
  }
)

phase('ReadSections')

// Select up to 10 sections: high first, then partial
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

const readArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`).join(' ')
log(`Reading ${sectionsToRead.length} sections: ${readArgs}`)

const sectionsContent = await agent(
  `Run the following bash command and return the complete output verbatim:

bash /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh ${readArgs}

Return the raw output as a single string field "content".`,
  {
    label: 'read-sections',
    phase: 'ReadSections',
    schema: {
      type: 'object',
      properties: {
        content: { type: 'string' }
      },
      required: ['content']
    }
  }
)

phase('GenerateAnswer')

const answerResult = await agent(
  `You are generating a Japanese answer about Nablarch 6 Bean Validation Form unit testing.

## Query
Bean ValidationのFormクラスの単体テストを書きたい。テストクラスの作り方とテストデータの準備方法を教えてほしい

## Section Content
${sectionsContent.content}

## Task
Generate a Japanese answer in this format:

**結論**: Direct answer (1-2 sentences with specific class/method names)

**根拠**: Code examples and spec information supporting the conclusion (code blocks, organized by implementation flow)

**注意点**: Constraints and common mistakes (omit if nothing applies)

参照: Only sections actually cited (file.json:sN format, omit category path)

Stay within 500 tokens (up to 800 for complex questions).

Then verify: check all Nablarch-specific claims (API names, class names, config methods, behavior specs, constraints, parameters) are supported by the section content.

Return:
{
  "answer_text": "<the answer in Japanese markdown>",
  "verify_result": "PASS or FAIL",
  "issues": ["list of unsupported claims if FAIL"],
  "used_sections": [{"ref": "file.json:sN", "reason": "why used"}],
  "unused_sections": [{"ref": "file.json:sN", "reason": "why not used"}]
}`,
  {
    label: 'generate-answer',
    phase: 'GenerateAnswer',
    schema: {
      type: 'object',
      properties: {
        answer_text: { type: 'string' },
        verify_result: { type: 'string', enum: ['PASS', 'FAIL'] },
        issues: { type: 'array', items: { type: 'string' } },
        used_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        },
        unused_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        }
      },
      required: ['answer_text', 'verify_result', 'issues', 'used_sections', 'unused_sections']
    }
  }
)

let finalAnswer = answerResult.answer_text

if (answerResult.verify_result === 'FAIL') {
  log(`Verify FAIL — regenerating without: ${answerResult.issues.join(', ')}`)
  const regenResult = await agent(
    `You are regenerating a Japanese answer about Nablarch 6 Bean Validation Form unit testing.

The previous answer had unsupported claims. Do NOT include these claims:
${answerResult.issues.map(i => '- ' + i).join('\n')}

## Query
Bean ValidationのFormクラスの単体テストを書きたい。テストクラスの作り方とテストデータの準備方法を教えてほしい

## Section Content
${sectionsContent.content}

Generate answer in the same Japanese format as before, but WITHOUT the unsupported claims listed above.

Return: { "answer_text": "<the answer>" }`,
    {
      label: 'regenerate-answer',
      phase: 'GenerateAnswer',
      schema: {
        type: 'object',
        properties: {
          answer_text: { type: 'string' }
        },
        required: ['answer_text']
      }
    }
  )
  finalAnswer = regenResult.answer_text
}

return {
  searchResult,
  sectionsToRead,
  sectionsContent: sectionsContent.content,
  answerResult,
  finalAnswer
}

